# Read current file
with open(r'C:\Apps\vocab-cards\data\confusables.json', 'r', encoding='utf-8') as f:
    data = json.load(f)

# Add SVGs to words in the list
for word_entry in data['words']:
    if 'word' in word_entry and word_entry['word'] in svgs:
        word_entry['svg'] = svgs[word_entry['word']]

# Write back
with open(r'C:\Apps\vocab-cards\data\confusables.json', 'w', encoding='utf-8') as f:
    json.dump(data, f, ensure_ascii=False, indent=2)

print('SVGs added successfully')
print(f'Total SVG additions: {sum(1 for w in data["words"] if "word" in w and w.get("svg", "").startswith("<svg"))}')
